interface FormProps {
  children: React.ReactNode;
  action?: (formData: FormData) => Promise<void>;
}

export default function Form({ children, action }: FormProps) {
  return (
    <form className="mb-6 flex flex-col gap-1" action={action}>
      {children}
      <input
        className="mt-4 self-end bg-gray px-4 py-2 text-white dark:bg-white dark:text-gray rounded-md cursor-pointer hover:opacity-80 font-semibold"
        type="submit"
        value="Enviar"
      />
    </form>
  );
}
